import{_ as o,o as a,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const w=JSON.parse('{"title":"33. Allowances Related To Overtime","description":"","frontmatter":{"title":"33. Allowances Related To Overtime","eba":"Nurses and Midwives 2024-2028","topics":["hours","overtime","shift-work","allowances"]},"headers":[],"relativePath":"ebas/nurses-midwives/allowances/33-allowances-related-to-overtime.md","filePath":"ebas/nurses-midwives/allowances/33-allowances-related-to-overtime.md"}'),r={name:"ebas/nurses-midwives/allowances/33-allowances-related-to-overtime.md"};function l(s,e,i,p,d,c){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_33-allowances-related-to-overtime" tabindex="-1">33. Allowances Related To Overtime <a class="header-anchor" href="#_33-allowances-related-to-overtime" aria-label="Permalink to &quot;33. Allowances Related To Overtime&quot;">​</a></h1><p><strong>33.1</strong> Meal allowance</p><p><strong>(a)</strong> Meals where overtime worked beyond one hour</p><p>An Employee who works overtime will in the circumstances described in subclause 33.1(b) receive either:</p><p><strong>(i)</strong> where an Employer has its own cooking and dining facilities, an adequate meal; or</p><p><strong>(ii)</strong> the relevant meal allowance as set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>.</p><p><strong>(b)</strong> Qualification for meal or payment</p><p><strong>(i)</strong> The entitlement under subclause 33.1(a) arises where in addition to a shift an Employee is required to work more than:</p><p><strong>(A)</strong> one hour beyond the usual finishing hour of work (Monday to Sunday inclusive) in which case the relevant allowance is &#39;Allowance A&#39;; or</p><p><strong>(B)</strong> five hours beyond the usual finishing hour of work (Monday to Sunday inclusive) in which case the relevant allowances are &#39;Allowance A&#39; and &#39;Allowance B&#39;.</p><p><strong>(ii)</strong> The entitlement under subclause 33.1(a) arises where, on a rostered day off an Employee is required to work more than:</p><p><strong>(A)</strong> five hours overtime, in which case the relevant allowance is &#39;Allowance A&#39;; or</p><p><strong>(B)</strong> nine hours overtime, in which case the relevant allowances are &#39;Allowance A&#39; and &#39;Allowance B&#39;.</p><p><strong>(c)</strong> Where provision does not apply</p><p>The allowance described at subclauses 33.1(b)(i) and 33.1(b)(ii) above is not payable where the Employee:</p><p><strong>(i)</strong> receives an adequate meal as described at subclause 33.1(a)(i); or</p><p><strong>(ii)</strong> the Employee could reasonably return home for a meal within the period allowed.</p><p><strong>(d)</strong> Same day payment</p><p>On request meal money will be paid on the same day overtime is worked where practicable.</p><p><strong>(e)</strong> Payments are in addition</p><p>The payment of a meal allowance under this clause is in addition to any overtime payment.</p><p><strong>33.2</strong> On Call Allowance</p><p><strong>(a)</strong> An Employee may be rostered to be &quot;on call&quot;.</p><p><strong>(b)</strong> On call means available to be recalled to duty in that period of time beyond the Employee&#39;s rostered hours of duty.</p><p><strong>(c)</strong> An Employee rostered to be on call will be paid the &quot;on call allowance&quot; set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, Part 2, per 12-hour period or part thereof commencing with the following rates from 17 May 2024:</p><p><strong>(i)</strong> Monday to Friday inclusive - $77.20;</p><p><strong>(ii)</strong> Saturday - $115.80;</p><p><strong>(iii)</strong> Sunday or public holiday - $135.10; and</p><p><strong>(iv)</strong> Weekend public holiday - $202.70.</p><p><strong>(d)</strong> The telephone allowance in the 2020 Agreement does not apply from 1 May 2024 and has been included in the rates at 33.2(c)(i) above.</p><p><strong>(e)</strong> An Employee rostered to be on call for a period spanning two days over which two different on call allowances apply will receive a payment which is equal to the allowance payable for the day attracting the higher allowance.</p><p><strong>33.3</strong> Travel and Recall</p><p><strong>(a)</strong> Employees recalled to work outside their ordinary rostered hours and using their own vehicle for transport to the place of work and return will receive the vehicle allowance as per <a href="/eba/ebas/nurses-midwives/allowances/36-vehicle-allowance.html">clause 36</a> (Vehicle Allowance) for reasonable kilometres travelled.</p><p><strong>(b)</strong> Employees rostered on call and recalled who do not use their own vehicle will, at the expense of the Employer, be provided with suitable transport to the place of work. The return journey will be in accordance with <a href="/eba/ebas/nurses-midwives/hours-of-work/49-overtime.html">clause 49.6</a> (Transport following overtime – all Employees).</p><p>Plain language terms: OT, extra hours, time and a half, double time, additional hours.</p>',35)])])}const m=o(r,[["render",l]]);export{w as __pageData,m as default};
